
<template>
    <div class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4" :class="{ fullscreen: isFullscreen }">
        <!-- HEADER -->
        <div
            class="widget-header graph-widget-heading float-left w-100 d-flex justify-content-between align-items-center">
            <div class="widget-title">
                <em class="fa fa-flag"></em> {{ $t('FlagReasonReport') }}
            </div>

            <!-- FULLSCREEN BUTTON -->
            <div class="widget-actions">
                <em :class="isFullscreen ? 'fas fa-compress' : 'fas fa-expand'" @click="toggleFullscreen"
                    style="cursor:pointer;font-size:16px" title="Toggle Fullscreen"></em>
            </div>
        </div>

        <!-- CHART -->
        <div id="FlagReasonReport" class="chart-container"></div>
    </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';
import { analyticsService } from '../../../../services/analyticsService';

export default {
    name: 'AgentPerformance',

    data() {
        return {
            loading: false,
            FlagResonData: [],
            FlagReason: [],
            FlagRecords: [],
            isFullscreen: false // ✅ fullscreen state
        };
    },

    mounted() {
        this.loadData();

        // ✅ ESC key exits fullscreen
        window.addEventListener('keydown', this.handleEsc);
    },

    beforeUnmount() {
        window.removeEventListener('keydown', this.handleEsc);
    },

    methods: {

        /* ==============================
           FULLSCREEN
        ============================== */

        toggleFullscreen() {
            this.isFullscreen = !this.isFullscreen;

            this.$nextTick(() => {
                Plotly.Plots.resize('FlagReasonReport');
            });
        },

        handleEsc(e) {
            if (e.key === 'Escape' && this.isFullscreen) {
                this.toggleFullscreen();
            }
        },

        /* ==============================
           LABEL WRAP
        ============================== */

        wrapLabel(text, maxLength = 18) {
            if (!text) return text;

            const words = text.split(' ');
            let lines = [];
            let currentLine = '';

            words.forEach(word => {
                if ((currentLine + word).length > maxLength) {
                    lines.push(currentLine.trim());
                    currentLine = word + ' ';
                } else {
                    currentLine += word + ' ';
                }
            });

            lines.push(currentLine.trim());

            return lines.join('<br>');
        },

        /* ==============================
           LOAD DATA
        ============================== */

        async loadData() {
            this.loading = true;

            try {
                const response = await analyticsService.GetFlagReasonData();

                if (response?.data?.result) {

                    let result = response.data.result;

                    if (typeof result === 'string') {
                        result = JSON.parse(result);
                    }

                    if (Array.isArray(result) && typeof result[0] === 'string') {
                        result = JSON.parse(result[0]);
                    }

                    const dataArray = result.Data || [];

                    this.FlagResonData = dataArray;
                    this.FlagReason = dataArray.map(x => x.flag_reason);
                    this.FlagRecords = dataArray.map(x => x.FlagRecords);

                    this.drawChart();
                }
            } catch (error) {
                console.error('Error loading flag reason data:', error);
            } finally {
                this.loading = false;
            }
        },

        /* ==============================
           DRAW CHART
        ============================== */

        drawChart() {

            const wrappedLabels = this.FlagReason.map(label =>
                this.wrapLabel(label, 18)
            );

            const trace = {
                x: wrappedLabels,
                y: this.FlagRecords,
                type: 'bar',
                marker: { color: '#003f5c' }
            };

            const layout = {
                margin: { t: 30, b: 180, l: 50, r: 30 },
                paper_bgcolor: 'transparent',
                plot_bgcolor: 'transparent',
                autosize: true,

                xaxis: {
                    tickangle: -90,
                    automargin: true,
                    tickfont: { size: 11 }
                },

                yaxis: {
                    automargin: true
                }
            };

            Plotly.newPlot(
                'FlagReasonReport',
                [trace],
                layout,
                {
                    responsive: true,
                    displaylogo: false,
                    modeBarButtons: [["toImage"]],
                    toImageButtonOptions: {
                        format: "png",
                        filename: "Flag_Reason",
                        height: 700,
                        width: 1000,
                        scale: 2
                    }
                }
            );
        }
    }
};
</script>

<style scoped>
/* ==============================
   NORMAL CHART HEIGHT
============================== */
.chart-container {
    width: 100%;
    height: 600px;
}

/* ==============================
   FULLSCREEN MODE
============================== */
.fullscreen {
    position: fixed !important;
    inset: 0;
    width: 100vw !important;
    height: 100vh !important;
    z-index: 999999999999999999999999999;
    margin: 0 !important;
    padding: 20px;
    background: #ffffff;
}

.fullscreen .chart-container {
    height: calc(100vh - 80px) !important;
}

/* smooth transition */
.widget-card {
    transition: all 0.25s ease;
}
</style>