<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">

    <!-- HEADER -->
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title d-flex justify-content-between align-items-center w-100">
        <span>
        <em class="fas fa-dollar"></em>
        {{ $t("AverageRevenueperClientContracts") }}
        </span>
            <button class="fullscreen-btn" @click="openFullscreen">
          <em class="fas fa-expand"></em>
        </button>
      </div>
    </div>

    <!-- CHART -->
    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="revenuePerClientChart" class="chart-container"></div>

    <!-- MINI STATS -->
    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(MaxRevPerClient) }}</div>
        <div class="mini-stat-label">{{ $t('MaxRevenueClient') }}</div>
      </div>

      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(AvgRevPerClient) }}</div>
        <div class="mini-stat-label">{{ $t('AverageQuarterly') }}</div>
      </div>
    </div>

    <!-- ================= FULLSCREEN ================= -->
    <div v-if="isFullscreen" class="fullscreen-overlay">

      <div class="fullscreen-header">
        <span>{{ $t("AverageRevenueperClientContracts") }}</span>

        <button class="close-btn" @click="closeFullscreen">
          <i class="fas fa-times"></i>
        </button>
      </div>

      <div id="revenuePerClientChartFullscreen"
           class="fullscreen-chart"></div>

    </div>

  </div>
</template>

<script>
import * as Plotly from "plotly.js-dist";

export default {
  name: "RevenuePerClientWidget",

  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    MaxRevPerClient: Number,
    AvgRevPerClient: Number
  },

  data() {
    return {
      loading: false,
      quarters: [],
      revenues: [],
      isFullscreen: false
    };
  },

  mounted() {
    this.loadData();
    window.addEventListener("keydown", this.handleEsc);
  },

  beforeUnmount() {
    window.removeEventListener("keydown", this.handleEsc);
  },

  methods: {

    /* ================= LOAD DATA ================= */
    loadData() {
      this.loading = true;

      try {
        this.quarters =
          this.QuarterlyTrendAnalysisData.map(d => d.Quarter_Label);

        this.revenues =
          this.QuarterlyTrendAnalysisData.map(
            d => d.Total_Revenue / d.Unique_Clients
          );

        this.drawChart("revenuePerClientChart", 280);

      } catch (error) {
        console.error("Revenue per Client error:", error);
      } finally {
        this.loading = false;
      }
    },

    /* ================= DRAW CHART ================= */
    drawChart(containerId, height) {

      const trace = {
        x: this.quarters,
        y: this.revenues,
        type: "scatter",
        mode: "lines+markers",
        line: { color: "#6366f1", width: 3 },
        marker: { size: 6 }
      };

      const layout = {
        margin: { t: 40, b: 70, l: 60, r: 40 },
        paper_bgcolor: "transparent",
        plot_bgcolor: "transparent",
        height: height
      };

      Plotly.newPlot(
        containerId,
        [trace],
        layout,
        {
          responsive: true,
          displaylogo: false,
          modeBarButtons: [["toImage"]],
          toImageButtonOptions: {
            format: "png",
            filename: "Average_Revenue_per_Clients",
            height: 700,
            width: 1200,
            scale: 2
          }
        }
      );
    },

    /* ================= FULLSCREEN ================= */

    openFullscreen() {
      this.isFullscreen = true;

      this.$nextTick(() => {
        this.drawChart(
          "revenuePerClientChartFullscreen",
          window.innerHeight - 120
        );
      });
    },

    closeFullscreen() {
      this.isFullscreen = false;
    },

    handleEsc(e) {
      if (e.key === "Escape") {
        this.closeFullscreen();
      }
    }
  }
};
</script>

<style scoped>

/* chart */
.chart-container {
  width: 100%;
  height: 280px;
}

/* header actions */
.widget-actions {
  float: right;
}

.fullscreen-btn {
  border: none;
  background: transparent;
  cursor: pointer;
  font-size: 16px;
  color: #6b7280;
}

.fullscreen-btn:hover {
  color: #111827;
}

/* ================= FULLSCREEN ================= */

.fullscreen-overlay {
  position: fixed;
  inset: 0;
  background: #ffffff;
  z-index: 9999999999;
  display: flex;
  flex-direction: column;
}

.fullscreen-header {
  height: 60px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0 25px;
  border-bottom: 1px solid #e5e7eb;
  font-weight: 600;
  font-size: 18px;
}

.fullscreen-chart {
  flex: 1;
  width: 100%;
}

.close-btn {
  border: none;
  background: transparent;
  font-size: 20px;
  cursor: pointer;
}

/* mini stats */
.mini-stats {
  display: flex;
  justify-content: space-around;
  padding: 10px 0;
}

.mini-stat-value {
  font-weight: 600;
}

.mini-stat-label {
  font-size: 12px;
  color: #6b7280;
}

</style>